@endsection @push('scripts')<script>document.getElementById('send-location').addEventListener('click',function(){const out=document.getElementById('location-result');if(!navigator.geolocation){out.textContent='Browser geolocation is unavailable.';return}out.textContent='Requesting permission…';navigator.geolocation.getCurrentPosition(async p=>{const r=await fetch(@json(route('worker.location-pings.store')),{method:'POST',headers:{'Content-Type':'application/json','X-CSRF-TOKEN':document.querySelector('meta[name=csrf-token]').content,'Accept':'application/json'},body:JSON.stringify({order_id:{{ $order->id }},latitude:p.coords.latitude,longitude:p.coords.longitude,accuracy_meters:p.coords.accuracy,heading:p.coords.heading,speed_mps:p.coords.speed,captured_at:new Date(p.timestamp).toISOString(),consent:true})});const d=await r.json();out.textContent=r.ok?d.message+' Accuracy: '+d.accuracy_meters+' m':Object.values(d.errors||{error:d.message}).flat().join(' ')},e=>out.textContent='Location was not sent: '+e.message,{enableHighAccuracy:true,timeout:15000,maximumAge:0})})</script>@endpush
